const { ideaPrompt, briefId } = $input.first().json.body;

// Build YouTube search queries
const queries = [
  `${ideaPrompt.slice(0, 80)} tutorial`,
  `${ideaPrompt.slice(0, 80)} implementation guide`,
];

return queries.map(q => ({ json: { query: q, briefId } }));

// Process YouTube search results
const allSources = [];

for (const item of $input.all()) {
  const items = item.json?.items;
  if (!items) continue;

  for (const video of items) {
    const snippet = video.snippet;
    if (!snippet) continue;

    const videoId = video.id?.videoId;
    if (!videoId) continue;

    // YouTube trust score: 55-70 (moderate, as video content is less precise than code)
    const trustScore = 60;

    allSources.push({
      sourceType: 'youtube',
      url: `https://www.youtube.com/watch?v=${videoId}`,
      title: snippet.title?.slice(0, 500) || 'Untitled Video',
      snippet: snippet.description?.slice(0, 300) || '',
      trustScore,
      rawPayload: {
        source: 'n8n',
        workflowType: 'youtube_research',
        channelTitle: snippet.channelTitle,
        publishedAt: snippet.publishedAt,
        videoId
      }
    });
  }
}

// Deduplicate by videoId
const seen = new Set();
const unique = allSources.filter(s => {
  const vid = s.rawPayload?.videoId;
  if (seen.has(vid)) return false;
  seen.add(vid);
  return true;
}).slice(0, 5);

return [{ json: {
  sources: unique,
  metadata: {
    workflowName: 'nexus-youtube-research',
    totalVideos: unique.length
  }
}}];
